//----------------------------------------------------------------------
// Drive stimulus 20% of the clock period after posedge clk
// (time units are set by the sim filelist's -timescale).
//----------------------------------------------------------------------

interface bus_if (input clk, input rst_n);
  // Generated signals from config
  logic dut_low;

  // Bidirectional (`inout`) nets. The DUT and the TB share the wire, so the TB must be
  // able to RELEASE it — hence a `wire` (resolved from both sides) plus a drive value and
  // an output enable that the driver owns.
  wire  sda;        // the RESOLVED line (what everyone sees)
  logic sda_o;      // what WE drive
  logic sda_oe;     // ...and whether we drive at all
  // OPEN-DRAIN: a driver may only pull LOW or release — it can never drive high. So
  // driving a 1 IS releasing, which is why the wired-AND works.
  assign sda = (sda_oe && !sda_o) ? 1'b0 : 1'bz;
  // The pullup. NOT a `pullup` primitive: primitives are illegal inside an interface
  // (*E,INFINS). A weak continuous assign is the legal equivalent — it loses to any real
  // driver and wins only when everyone has released, which is exactly a pullup.
  assign (weak1, weak0) sda = '1;   // nobody driving => reads 1, not X

  // pragma quickuvm custom signals_additional begin
  // pragma quickuvm custom signals_additional end

  clocking cb1 @(posedge clk);
    default input #1step output #2;
    input  dut_low;
    // We drive <n>_o/<n>_oe and sample the RESOLVED <n> — never the value we drove.
    output sda_o, sda_oe;
    input  sda;

    // pragma quickuvm custom clocking_block_additional begin
    // pragma quickuvm custom clocking_block_additional end
  endclocking
endinterface
